function generateIndustryPage([slug, phrase, titleIndustry, services]) {
  const capitalizedPhrase = phrase.charAt(0).toUpperCase() + phrase.slice(1)

  return {
    type: 'industry',
    industry: phrase,
    slug: `/government-contracts-for-${slug}`,
    title: `Government Contracts for ${titleIndustry}`,
    metaTitle: `Government Contracts for ${titleIndustry} | DeliveryLink`,
    metaDescription: `Learn how ${phrase} can prepare for government contracts with SAM.gov readiness, capability statements, opportunity targeting, and a free readiness review.`,
    excerpt: `A federal contracting readiness guide for ${phrase} that want to sell services to agencies, primes, schools, municipalities, and public institutions.`,
    keywords: [`government contracts for ${phrase}`, `${phrase} government contracts`, `${phrase} federal contracts`, 'SAM.gov readiness', 'capability statement'],
    faq: [
      [`Can ${phrase} win government contracts?`, `Yes. ${capitalizedPhrase} can compete when they package their services clearly, complete required registrations, understand buyer requirements, and pursue realistic opportunities that match their capacity.`],
      [`What registrations do ${phrase} need?`, `Most companies preparing for direct federal awards should confirm business entity details, EIN, UEI, SAM.gov status, NAICS alignment, and accurate points of contact before bidding.`],
      [`Do ${phrase} need a capability statement?`, `Yes. A capability statement helps buyers and prime contractors quickly understand services, differentiators, past performance, service area, codes, and contact information.`],
      [`What is the best first step for ${phrase}?`, `The best first step is a readiness review that identifies missing registrations, weak positioning, unclear NAICS codes, capability statement gaps, and the next five actions.`],
    ],
    sections: [
      [`Why ${phrase} should look at government contracts`, `Government buyers routinely need dependable vendors for ${services}. Public agencies operate facilities, programs, fleets, offices, campuses, infrastructure, and community services that require outside support. For ${phrase}, the opportunity is not just one large federal contract. It can include subcontracting with primes, local government work, school district purchasing, state opportunities, municipal work, and targeted federal awards. The key is to understand where your service fits and which buyers already purchase similar work.`, `The mistake many owners make is searching for contracts before proving readiness. A buyer wants to know that your business is legitimate, reachable, capable, and prepared to perform under public-sector expectations. That means registrations, identifiers, insurance or licenses where relevant, a clear scope of service, past performance, and a capability statement that translates your commercial work into procurement language.`],
      [`What buyers expect from ${phrase}`, `Government buyers are not simply looking for the cheapest vendor. They are trying to reduce risk. For ${phrase}, risk can include missed deadlines, poor documentation, inconsistent staffing, unclear pricing, safety issues, compliance failures, or inability to scale. Your marketing and proposal materials should show how you reduce those risks. Explain your process, quality controls, response capacity, supervision, tools, service area, and communication rhythm.`, `Specific evidence matters. If you serve commercial clients, describe the size of the accounts, frequency of service, response times, staffing model, equipment, software, certifications, safety practices, and measurable outcomes. Even when you do not have government past performance, relevant commercial work can help buyers understand your ability to perform similar public-sector work.`],
      [`Registrations and identifiers for ${phrase}`, `Before pursuing direct awards, confirm the administrative foundation. Your company information should be consistent across formation documents, tax records, banking records, SAM.gov, insurance documents, and capability materials. If your legal name, address, or contact information does not match, registration and validation can slow down. This is especially painful when an opportunity deadline is close.`, `For federal work, a UEI and active SAM.gov registration may be necessary for direct awards. Some businesses also need licenses, insurance, bonding, background checks, safety documentation, or industry-specific certifications depending on the service and jurisdiction. A readiness review helps determine which items are blockers and which items are simply helpful.`],
      [`NAICS codes and opportunity targeting`, `NAICS codes help buyers and systems categorize your business. ${capitalizedPhrase} should choose codes based on actual services and real buying patterns, not guesses. Start with the work you can perform today, then compare those services against solicitations, award history, agency forecasts, and prime contractor needs. The best code is not always the most obvious one.`, `Opportunity targeting should be narrow at first. Focus on a few agencies, regions, or prime contractors that already buy your type of service. Look for recurring work, manageable contract size, realistic performance locations, and requirements that match your team. This prevents wasted time and helps build momentum.`],
      [`Capability statement strategy`, `A capability statement for ${phrase} should be direct and buyer-focused. Include core services, differentiators, relevant past performance, service area, NAICS codes, UEI or SAM status if available, contact details, and proof that you can deliver. Avoid generic language like “quality service” unless you support it with evidence.`, `Use buyer language. If your service involves scheduled maintenance, emergency response, route coverage, quality inspections, compliance documentation, secure access, staffing, or specialized equipment, say so clearly. Buyers and primes should understand in less than one minute where your company fits.`],
      [`Prime contractor and subcontracting path`, `Subcontracting can be one of the fastest ways for ${phrase} to enter the government market. Prime contractors often need reliable specialty vendors, local service providers, surge capacity, and companies that can perform defined scopes. A smaller business can build past performance and learn public-sector expectations through this path.`, `The outreach should be specific. Do not send a vague introduction. Explain what services you provide, where you operate, what makes you reliable, and which contract categories or agencies you can support. Attach a tailored capability statement and make the next step easy.`],
      [`Pricing and proposal readiness`, `Public-sector pricing requires discipline. Your price should account for labor, materials, supervision, travel, insurance, equipment, reporting, compliance time, administrative overhead, and profit. Underpricing may win attention but can damage the business if performance costs are higher than expected.`, `Before bidding, build a simple pricing model and a bid/no-bid checklist. Ask whether the opportunity matches your capacity, whether you understand the scope, whether the deadline is realistic, whether you can document compliance, and whether the contract would be profitable. Good contractors say no to bad-fit opportunities.`],
      [`The fastest next step`, `The fastest next step for ${phrase} is not to bid immediately. It is to identify what is missing and fix the highest-impact gaps. That may mean completing SAM.gov registration, requesting or confirming a UEI, improving the capability statement, narrowing target agencies, validating NAICS codes, or preparing a subcontractor outreach list.`, `DeliveryLink’s free Government Contract Readiness Review gives ${phrase} a practical score, identifies missing registrations, reviews capability positioning, and provides the next five actions. The goal is simple: stop guessing and start moving through a clear federal contracting plan.`],
    ],
  }
}

const INDUSTRY_SEO_PAGES = INDUSTRIES.map(generateIndustryPage)

export const SEO_PAGES = [...CORE_SEO_PAGES, ...INDUSTRY_SEO_PAGES]

export { ctaText, INDUSTRY_SEO_PAGES }
